inductive Cs (p : ℕ) (var : Type) : Type where
  | nil : Cs p var
  | eq0 : Exp (ZMod p) var -> Cs p var -> Cs p var
  | lam : (var -> Cs p var) -> Cs p var

def Cs' (p : ℕ) : Type _ := (var:Type) -> Cs p var

